module frequency_divider (
    input clk,
    input rst,
    output reg clk_out
);
    reg [2:0] countdown;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            countdown <= 3'b000;
            clk_out <= 0;
        end else begin
            countdown <= countdown + 1;
            if (countdown == 3'b111) begin
                clk_out <= ~clk_out;
                countdown <= 3'b000;
            end
        end
    end
endmodule
